const express = require('express');
const helmet = require('helmet');
const rateLimit = require('express-rate-limit');
const { param, validationResult } = require('express-validator');

const app = express();

// --- Security & hardening middleware ---
app.disable('x-powered-by');
app.set('trust proxy', 1); // if behind a proxy/LB
app.use(helmet());
app.use(express.json({ limit: '10kb' })); // cap body size
app.use(rateLimit({
  windowMs: 60 * 1000,
  max: 100,
  standardHeaders: true,
  legacyHeaders: false,
}));

// --- Routes ---
app.get('/health', (req, res) => {
  res.json({ status: 'ok', timestamp: new Date().toISOString() });
});

app.get('/users', (req, res) => {
  // In real code, pull from a data layer with try/catch or async handler wrapper
  res.json([
    { id: 1, name: 'Alice', email: 'alice@example.com' },
    { id: 2, name: 'Bob', email: 'bob@example.com' },
  ]);
});

// Example validated route pattern for future use
app.get(
  '/users/:id',
  param('id').isInt({ min: 1, max: 2_147_483_647 }).toInt(),
  (req, res, next) => {
    const errors = validationResult(req);
    if (!errors.isEmpty()) {
      return res.status(400).json({ error: 'Invalid input' });
    }
    // ... lookup logic
    res.json({ id: req.params.id });
  }
);

// --- 404 + error handler (must be last) ---
app.use((req, res) => res.status(404).json({ error: 'Not found' }));

// eslint-disable-next-line no-unused-vars
app.use((err, req, res, _next) => {
  // Log with a structured logger in real code (pino/winston), never leak err.stack
  console.error({ msg: 'unhandled_error', err: err.message });
  res.status(err.status || 500).json({ error: 'Internal server error' });
});

// --- Server lifecycle ---
const PORT = Number(process.env.PORT) || 3000;
const server = app.listen(PORT, () => {
  console.log(JSON.stringify({ msg: 'server_started', port: PORT }));
});

function shutdown(signal) {
  console.log(JSON.stringify({ msg: 'shutdown', signal }));
  server.close(() => process.exit(0));
  setTimeout(() => process.exit(1), 10_000).unref(); // force-exit safeguard
}
process.on('SIGTERM', () => shutdown('SIGTERM'));
process.on('SIGINT', () => shutdown('SIGINT'));
process.on('unhandledRejection', (reason) => {
  console.error({ msg: 'unhandled_rejection', reason: String(reason) });
});
process.on('uncaughtException', (err) => {
  console.error({ msg: 'uncaught_exception', err: err.message });
  shutdown('uncaughtException');
});

module.exports = app;
