  limit: z.coerce.number().int().min(1).max(100).optional(),
});

app.get('/users', (req, res, next) => {
  try {
    const { limit } = listUsersSchema.parse(req.query);
    const users = [
      { id: 1, name: 'Alice' },
      { id: 2, name: 'Bob' },
    ];
    res.json(limit ? users.slice(0, limit) : users);
  } catch (err) {
    next(err);
  }
});

// --- 404 handler ---
