  console.error(err); // use a structured logger (pino/winston) in real apps
  const status = err.status || 500;
  res.status(status).json({
    error: status === 500 ? 'Internal Server Error' : err.message,
  });
});

// 404 handler
app.use((req, res) => res.status(404).json({ error: 'Not Found' }));

process.on('unhandledRejection', (reason) => { console.error(reason); });
process.on('uncaughtException', (err) => { console.error(err); process.exit(1); });

const server = app.listen(3000, () => console.log('Server on :3000'));
server.on('error', (err) => { console.error('Listen failed:', err); process.exit(1); });
```

## 2. Missing input validation

Even though current routes don't take user input, you should establish the pattern now.

**Recommendation:** Use a schema validator like `zod` or `joi` for every route that accepts params, query, or body:
```js
const { z } = require('zod');

const userIdSchema = z.object({ id: z.coerce.number().int().positive() });

app.get('/users/:id', (req, res, next) => {
  const parsed = userIdSchema.safeParse(req.params);
  if (!parsed.success) return res.status(400).json({ error: 'Invalid id' });
  // ... lookup with parsed.data.id
});
```
Also add `express.json({ limit: '100kb' })` when you start accepting bodies — prevents memory-exhaustion DoS via huge payloads.

## 3. Security headers & hardening

**Missing entirely:**
- `helmet` — sets `X-Content-Type-Options`, `Strict-Transport-Security`, `X-Frame-Options`, CSP, etc.
- CORS policy — currently undefined (browsers default-deny, but be explicit).
- Rate limiting — nothing prevents brute-force or DoS.
- `app.disable('x-powered-by')` — don't advertise Express version.

**Recommendation:**
