const helmet = require('helmet');
const rateLimit = require('express-rate-limit');
const { query, validationResult } = require('express-validator');

const app = express();
const PORT = process.env.PORT || 3000;

// --- Security middleware ---
app.disable('x-powered-by');
app.use(helmet());
app.use(express.json({ limit: '10kb' }));  // cap body size
app.use(rateLimit({ windowMs: 60_000, max: 100 }));

// --- Routes ---
app.get('/health', (req, res) => {
  res.json({ status: 'ok', timestamp: new Date().toISOString() });
});

app.get(
  '/users',
  [
    query('limit').optional().isInt({ min: 1, max: 100 }).toInt(),
    query('offset').optional().isInt({ min: 0 }).toInt(),
  ],
  (req, res, next) => {
    const errors = validationResult(req);
    if (!errors.isEmpty()) {
      return res.status(400).json({ error: 'Invalid query parameters', details: errors.array() });
    }
    try {
      const users = [
        { id: 1, name: 'Alice' },  // email omitted unless authorized
        { id: 2, name: 'Bob' },
      ];
      res.json(users);
    } catch (err) {
      next(err);
    }
  }
);

// --- 404 handler ---
app.use((req, res) => {
  res.status(404).json({ error: 'Not found' });
});

// --- Central error handler ---
// eslint-disable-next-line no-unused-vars
app.use((err, req, res, _next) => {
  // Log full error server-side, return sanitized message to client
  console.error({ msg: 'Unhandled error', err: err.stack, path: req.path });
  const status = err.status || 500;
  res.status(status).json({
    error: status === 500 ? 'Internal server error' : err.message,
  });
});

// --- Server lifecycle ---
const server = app.listen(PORT, () => {
  console.log(`Server running on port ${PORT}`);
});

const shutdown = (signal) => {
  console.log(`${signal} received, shutting down gracefully`);
  server.close(() => process.exit(0));
  setTimeout(() => process.exit(1), 10_000).unref();  // force-exit safety
};
process.on('SIGTERM', () => shutdown('SIGTERM'));
process.on('SIGINT', () => shutdown('SIGINT'));
process.on('unhandledRejection', (reason) => {
  console.error('Unhandled rejection:', reason);
});
process.on('uncaughtException', (err) => {
  console.error('Uncaught exception:', err);
  shutdown('uncaughtException');
});

module.exports = app;
```

## Priority Order

| Priority | Change | Why |
|----------|--------|-----|
| **High** | Central error handler + 404 handler | Prevents stack-trace leaks, consistent API responses |
| **High** | `helmet`, disable `x-powered-by`, body-size limit | Baseline hardening against common attacks |
| **High** | Rate limiter | Mitigates brute-force and DoS |
| **Medium** | Input validation via `express-validator` (or `zod`/`joi`) | Establishes a pattern for future routes |
| **Medium** | Graceful shutdown | Avoids dropped requests on deploys |
| **Medium** | Remove PII (email) from unauthenticated endpoint | PII minimization |
| **Low** | Structured logger (`pino`/`winston`) + request logging (`morgan`) | Audit trail |
| **Low** | `process.env.PORT` | Deploy flexibility |

