const helmet = require('helmet');
const rateLimit = require('express-rate-limit');

const app = express();

// --- Security middleware ---
app.disable('x-powered-by');
app.use(helmet());                                   // secure default headers
app.use(express.json({ limit: '10kb' }));            // cap body size
app.use(express.urlencoded({ extended: false, limit: '10kb' }));

// --- Rate limiting ---
app.use(rateLimit({
  windowMs: 60_000,
  max: 100,
  standardHeaders: true,
  legacyHeaders: false,
}));

// --- Routes ---
app.get('/health', (req, res) => {
  res.json({ status: 'ok', timestamp: new Date().toISOString() });
});

app.get('/users', (req, res) => {
  // TODO: require auth before returning PII
  res.json([
    { id: 1, name: 'Alice' },   // email removed until authz in place
    { id: 2, name: 'Bob' },
  ]);
});

// --- 404 handler ---
app.use((req, res) => {
  res.status(404).json({ error: 'Not Found' });
});

// --- Centralized error handler (must have 4 args) ---
// eslint-disable-next-line no-unused-vars
app.use((err, req, res, next) => {
  console.error('[error]', {
    msg: err.message,
    stack: err.stack,
    path: req.path,
  });
  const status = err.status || 500;
  res.status(status).json({
    error: status === 500 ? 'Internal Server Error' : err.message,
  });
});

// --- Process-level safety nets ---
process.on('unhandledRejection', (reason) => {
  console.error('[unhandledRejection]', reason);
});
process.on('uncaughtException', (err) => {
  console.error('[uncaughtException]', err);
  process.exit(1);   // fail fast; let orchestrator restart
});

// --- Graceful startup/shutdown ---
const PORT = Number(process.env.PORT) || 3000;
const server = app.listen(PORT, () => {
  console.log(`Server running on port ${PORT}`);
});

for (const sig of ['SIGTERM', 'SIGINT']) {
  process.on(sig, () => {
    console.log(`${sig} received, closing server`);
    server.close(() => process.exit(0));
    setTimeout(() => process.exit(1), 10_000).unref(); // hard cutoff
  });
